import{_ as p,o as e,c as a,j as r,a as t,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"诹访大明神","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/1.生理类/诹访大明神.md","filePath":"4.资源分区/1.血统与训练/1.生理类/诹访大明神.md"}'),n={name:"4.资源分区/1.血统与训练/1.生理类/诹访大明神.md"};function o(d,b,_,l,i,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"诹访大明神",tabindex:"-1"},[t("诹访大明神 "),r("a",{class:"header-anchor",href:"#诹访大明神","aria-label":'Permalink to "诹访大明神"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风020")])])],-1),s('<h1 id="诹访大明神-1" tabindex="-1">诹访大明神 <a class="header-anchor" href="#诹访大明神-1" aria-label="Permalink to &quot;诹访大明神&quot;">​</a></h1><p>诹访大明神</p><p>诹访子是居住在守矢神社的谜之神明，种族为八百万之神。八百万之神没有作为基本的灵魂，是由纯粹的信仰所组成的。拥有着统领祟神的力量，掌握着创造坤程度的能力。所带来的祟神的正体，是在外部世界被叫做御左口的土著神。所谓的土著神，就是只有在狭小的一块范围里被信仰的神明。虽说离开土地会失去信仰，但是限定在本土作战的话，拥有比在广泛范围被信仰的神明（即使是最高等级的神明）更强的力量的也不在少数。<br> 真正身份是洩矢神。现在常常与诹访地区其他传说的神明（包括一些作祟神）被视为同一位神明，<br> 不过在东方中，诹访子是能统领作祟神的神。<br> 本血统及所有能力皆作为自然本质。</p><p>“青蛙神”<br> D+600</p><p>神具「洩矢的铁轮」<br> *諏訪大明神絵詞》中记载，洩矢神和建御名方神作战的时候所使用的武器是铁轮。<br> 视为一件伤害6L的天生武器，若扔出视为一件伤害6L、体积2的投掷武器。</p><p>“ケロ帽”<br> 头盔位视为装备名为“ケロ帽”的斗笠，不可拆卸，不可与其他头盔装备叠加使用。“ケロ帽”现在为装备者提供盔甲防御1/1。可以用来避雨，任何看见过青蛙的智慧生物看见它会第一时间将二者联系起来。</p><p>「祟り」<br> 神 这个特性上，外形几乎没有意义”。（《求闻口授》）<br> 你无法购买变化。<br> 你掌握自然派系的D级派系造诣。<br> 目前还只是伪·八百万神，似乎还没受到信仰缺失的影响。<br> 开启诹访神技能树。<br> 你未购买专属专长神樱「湛樱花吹雪」(1)时不能进行施法检定。<br> （tips：专属专长在页末）</p><p>「名存实亡的神明」<br> 诹访子的王国曾遭到大和诸神的入侵，所谓来访王国的大和之神，正是神奈子。当然，诹访子进行了抵抗。她使用了当时最先进的铁制武器进行战斗。但是，神奈子施放了大量细小的植物藤蔓，使诹访子所拥有的大量铁轮全部锈蚀粉碎了。<br> 你获得腐蚀易伤3。</p><p>八百万诹访<br> C+1200</p><p>源符「诹访清水」<br> 諏訪清水是流经诹访大社上社前宫，被称为「水眼」的御手洗川源头的一条清流。因为流经神域，从古代开始就作为御神水被奉为至宝。起源于千米外的山中，最终汇入御手洗川。<br> 开启一个信仰池，其容量为风度+操控。每经过一场影片，这个信仰池便+1上限。受到来自各界诹访地区住民的信仰，你每天最多能恢复等同于信仰池上限三倍的信仰。在一次短休息结束后，你可以选择进行一个信仰关键属性检定，为你恢复成功数点信仰。<br> 你掌握自然派系的C级派系造诣。</p><p>开宴「二拜二拍一拜」<br> 你现在作为八百万神的一员，身体不再“那么的”有意义。当然，八百万神与任何一神论宗教里的全知全能神有着根本的区别——八百万神更接近于生物，只是生命的另一种存在形式罢了。<br> 一轮一次，在你受到伤害时，你可以至多消耗3点信仰以吸收其中的1点严重伤害。<br> 你的身体完全由信仰支撑着，失去全部信仰或许会消散吧。<br> 当你的信仰池为满时，你的所有检定都会获得1DP的完美加值。与此同时，当你的信仰归零时，你被视为不再拥有任何完好，直到你的信仰池恢复任意点的信仰。这代表当你再次受到伤害时，直接从扣除韧性计算。</p><p>“ケロ帽”<br> 头盔位视为装备名为“ケロ帽”的斗笠，不可拆卸，不可与其他头盔装备叠加使用。“ケロ帽”现在为装备者提供盔甲防御4/4。</p><p>神具「洩矢的铁轮」<br> 也有说法指铁轮是古代的祭祀器具。<br> 视为一件伤害6L，格挡1的天生武器，若扔出视为一件伤害6L的投掷武器，扔出后可使用一个移动动作使其立即回到你手里。每造成1点严重伤害将为你恢复1点信仰，但不能超过每日恢复上限。你的攻击范围内新增一个其他攻击目标。</p><p>创造坤程度的能力<br> 诹访子同样是大地之神。“坤”在八卦中表示“地”。<br> 动作：标准<br> 能耗：2点神力<br> 射程：10米<br> 范围：目标点为圆心，半径为2米的圆<br> 目标：射程内一点<br> 持续：立即<br> 效果：<br> 改变范围内土壤的形态，在以下效果中选取一样生效：<br> 1、令范围内的土地往任意方向移动10米，若土地上有其他单位，其也会跟着往该方向进行移动，其可以通过一个DC7的平衡检定令自身不进行位移。<br> 2、令范围内的土地长出尖刺，这会令范围内的单位受到10点穿刺伤害，反射豁免。<br> 3、令范围内的土地在一场景内视为无支线级别的困难地形。</p><p>永寿唯一诹访神<br> B+2650</p><p>土著神「小小青蛙不输风雨」<br> 她的王国却曾经受到过大和众神的入侵。诹访子使用当时最先进的铁器进行了旷日持久的抵抗，最终在明悟神力的巨大差距后投降。但是，洩矢之国的人们，没有忘记原来的土著神御社宫司神的恐怖，所以坚决不接受这新的神明。名义上支配了这个王国的新的神，在大和的神话里是个只有名字保存下来的神。实际上，诹访子是一直都支配着王国的。现在外面的神明已经基本被大和的神话所替换了，只有她一个人，仍然以古代的方式悄悄地获得着信仰。<br> 只要你的信仰尚未归零，你被视为拥有快速治疗1（12医疗点数），当你被断肢效果作用时，你的四肢将会遵循快速治疗规则而再生（包括头部）。<br> 你掌握自然派系的B级派系造诣。</p><p>“ケロ帽”<br> 头盔位视为装备名为“ケロ帽”的斗笠，不可拆卸，不可与其他头盔装备叠加使用。“ケロ帽”现在为装备者提供盔甲防御6/6，并带有1点全伤害吸收。</p><p>神具「洩矢的铁轮」<br> 幕府时代来临前，诹访地区的铁器工艺仍大大超过同时代本州岛其他地区的铁器工艺水平<br> 视为一件伤害9L，格挡1的天生武器，若扔出视为一件伤害9L的投掷武器，扔出后可使用一个移动动作使其立即回到你手里。每造成1点严重伤害将为你恢复1点信仰，但不能超过每日恢复上限。</p><p>大地之湖<br> 人们传说富士山曾与八岳比高，八岳比较高。因此愤怒的富士山把八岳削去一块变成了现在的高度。有的故事中还有个后续，是八岳的妹妹蓼科山为此事悲哀叹息，流下的泪水形成了诹访湖。<br> 但实际上，诹访湖其实是构造运动形成的。<br> 创造坤程度的能力射程提升至80米，范围提升至目标点为圆心，半径为40米的圆。<br> 获得等同于基础移动速度的遁地速度或固体物质穿行速度，遁力3。</p><p>土著神的顶点<br> A+5050</p><p>崇符「洩矢大人」<br> 赤口大人呀，让人分不清她到底是保佑丰收的神还是作祟的神。<br> 这回又是战神了吗？是不是还有更多的身份呀？（《文花贴DS》）<br> 洩矢神是持有道祖神、性神、蛇神、守屋神、农耕神、风水神等神性和多种信仰形态的自然神。现在在诹访地区一般将其和洩矢神、建御名方神视为同一神明。信仰范围遍及整个东日本，有多种称呼名讳，近二百种汉字写法。<br> 似乎是从绳文时代就开始存在至今的远古习俗信仰，作为原始的自然信仰难以确定其起源。另外在诹访地区，也常常将诹访蛇神与「ソソウ神」、水神、山神等的神性视为相同。<br> 只要你的信仰尚未归零，你被视为拥有4快速治疗（48医疗点数），并提升力量检定上的3点附加成功。<br> 你掌握自然派系的A级派系造诣。</p><p>“ケロ帽”<br> 头盔位视为装备名为“ケロ帽”的斗笠，不可拆卸，不可与其他头盔装备叠加使用。“ケロ帽”现在为装备者提供盔甲防御17/17，并带有1全伤害吸收。</p><p>神具「洩矢的铁轮」<br> 相传在诹访大战中，建御名方神则使用藤蔓让铁轮生锈腐朽，从而取得了胜利。也有说法认为指古代制铁技术的变迁，洩矢神象征用自然生成的湖沼铁和低温炉的旧制铁技术，建御名方神象征用砂铁和高温炉（鑪，たたら）的新制铁技术。建御名方神所持的「藤蔓」可能象征着新制铁技术中大量使用的木炭燃料。（《诹访大明神绘词》）<br> 视为一件伤害27L，格挡3，威猛5，破甲5的天生武器，若扔出视为一件伤害27L，高速5的投掷武器，具有回力特性。每轮一次，这一武器所造成的1点严重伤害将为你恢复1点信仰，但不能超过每日恢复上限。<br> 蛙休「长冬长眠」<br> 赤口归于土，御射归于石。<br> 一影片一次，当你死亡，你的遗体立即被土石包裹。你的意识将化为非具象的八百万神，于七日后重新降临于世界上。在此期间你除了观察与移动外无法进行更多的动作。你的遗体将获得你原来生命值点数的结构值，若被摧毁则复活失败。你每复活一次，信仰池上限永久降低1。这是一个A级、祝福来源的复活效果<br> 不过，就算这个长久以来不断取得的信仰，也在科学的时代来临时开始逐渐消失了。<br> 只要你的信仰尚未归零，你无需饮食、无需休息、无需呼吸，且免疫c级衰老。当你的信仰归零，你不被视为‘不再拥有任何完好’，而是视为受到自上一次饮食，休息以来的天数总和加6点数的严重伤害。</p><p>诹访神技能树</p><p>蛙狩「蛙以口鸣，方致蛇祸」<br> 类型：攻击技<br> 价格：D+750<br> 派系：自然<br> 花费：2<br> 成分：语言<br> 动作：标准<br> 射程：15米<br> 效果：单体<br> 持续：一轮<br> 日本谚语，因为蛇可以凭借蛙鸣声得知其所在而捕食之，故用于形容人说了多余的话而引祸上身，意同中文的“祸从口出”。<br> 御社宫司神是负责诞生、农业、军事，各种各样的事情的作祟神，同时也是只要受到一点轻视马上就会降下神罚将对方杀掉的恐怖神明。能够控制住这位神明的只有诹访子了。<br> 选择一个攻击范围内的敌对目标进行一次攻击检定以代表作祟，若成功造成了伤害，则转化为使其接下来一轮的任意检定获得3DP亵渎减值。这道法术一轮内仅允许使用一次。</p><p>合掌「大太法师的参拜」<br> 类型：攻击技<br> 价格：C+1000<br> 派系：自然<br> 花费：6<br> 成分：动作<br> 动作：标准<br> 射程：45米<br> 效果：单体<br> 持续：一场景<br> 大太法师，日本各地都有的民间传说，创造了山河和湖沼的巨人。<br> 你进行一次施法攻击检定，并选择射程内一名敌人进行一次强韧豁免对抗，若未通过，则其将被土石所包裹，受到差额的钝击伤害并在一场景内陷入C级环境来源的困难地形中。<br> 你可以通过差价购买B级合掌「大太法师的参拜」</p><p>合掌「大太法师的参拜」<br> 类型：攻击技<br> 价格：B+2500<br> 派系：自然<br> 花费：10<br> 成分：动作<br> 动作：整轮<br> 射程：风度*5米<br> 效果：群体<br> 持续：一场景<br> 巨量的土石海浪般压了过来。很可怕。(《非想天则》）<br> 你进行一次施法攻击检定，并选择射程内至多5名敌人进行一次强韧豁免对抗，若未通过，则其将被土石所包裹，受到二者差值的伤害，并再陷入B级环境来源的定身效果中，这个效果将持续一场景。</p><p>土著神「手长足长大人」（不提供属性点）<br> C+1000<br> 手長足長（てながあしなが）<br> 长野县诹访地区古时所信仰的神明“手長さま”（手摩乳命）和“足長さま”（足摩乳命），有用于祭祀的手长神社和足长神社。二神后来成为了诹访明神的下属。在日本东北地区的民间传说中，“手長足長”是一种巨人，其中一个手长，另外一个脚长。据说会吃掉游客，打翻船只<br> 据记载同样是古代日本神话“ヤマタノオロチ退治”（八岐大蛇退治）中所登场的夫妇神“アシナヅチ?テナヅチ”。《古事记》中记载为“足名椎命·手名椎命”，《日本书纪》中记载为“脚摩乳·手摩乳”。<br> 获得两个D级随从：崇神手长与崇神足长。</p><p>手长<br> ▓▓生理属性<br> ■力量6<br> ■敏捷6<br> ■耐力6<br> ▓▓心智属性<br> ■智力6<br> ■感知6<br> ■决心2<br> ▓▓互动属性<br> ■风度2<br> ■操控2<br> ■沉着2</p><p>▓▓生理系<br> ■运动3 反射3<br> ■求生5 长线治疗5 动物沟通3<br> ■射击1<br> ■武技3 拳3 刀3<br> ▓▓心智系<br> ■学识3 解读3<br> ■器用3<br> ■手艺5 修复制造物品5<br> ■专注1<br> ▓▓互动系<br> ■洞察1<br> ■隐秘1<br> ■表达1<br> ■社交1</p><p>体积5<br> 生命16<br> 防御预设：<br> 基础6+1</p><p>手长「宝永四年的赤蛙」<br> 宝永三年（1706年）年末除夕之夜，突然天降暴雨，连结冰的御手洗川都融解了，造成了洪水泛滥。在这种情况下，人们都认为已经不能再进行蛙狩神事了。孰料在宝永四年（1707年）的元月1日，神社前面突然出现了3只赤蛙，于是蛙狩神事得以继续进行。这就是就被称为诹访大社上社七不思议之一的「元朝の蛙狩」。手长，足长于诹访子本体正好组成三只赤蛙。<br> 召唤与收回手长均为一个迅捷动作，若手长已被召唤而出且正加护着你，则手长会如同全遮蔽一般为你抵挡所有你受到的伤害直至其进入昏迷。在提供加护时，只计算手长拥有的防御而不计算你的，若需要手长以豁免进行检定，则也使用手长的数据进行豁免。令手长加护于你是一个自由动作，但若它正为你提供保护，则它无法进行攻击或移动，也不视为具有行动点，不参与战斗轮。</p><p>足长<br> ▓▓生理属性<br> ■力量6<br> ■敏捷6<br> ■耐力4<br> ▓▓心智属性<br> ■智力4<br> ■感知6<br> ■决心2<br> ▓▓互动属性<br> ■风度2<br> ■操控2<br> ■沉着2</p><p>▓▓生理系<br> ■运动5 反射3<br> ■求生3 长线治疗3 动物沟通3<br> ■射击1<br> ■武技3 拳3<br> ▓▓心智系<br> ■学识1<br> ■器用3 操纵载具3<br> ■手艺1<br> ■专注1<br> ▓▓互动系<br> ■洞察5 搜索5 侦察5<br> ■隐秘1<br> ■表达1<br> ■社交1</p><p>体积5<br> 生命9<br> 防御预设：<br> 基础3+1</p><p>足长「宝永四年的赤蛙」<br> 宝永三年（1706年）年末除夕之夜，突然天降暴雨，连结冰的御手洗川都融解了，造成了洪水泛滥。在这种情况下，人们都认为已经不能再进行蛙狩神事了。孰料在宝永四年（1707年）的元月1日，神社前面突然出现了3只赤蛙，于是蛙狩神事得以继续进行。这就是就被称为诹访大社上社七不思议之一的「元朝の蛙狩」。手长，足长于诹访子本体正好组成三只赤蛙。<br> 召唤与收回足长均为一个自由动作，但在骑乘足长时，仍需先遵循驾驶载具规则登上足长。在你驾驭足长时，足长会视为一个移动速度为40米的轻载具，同时，足长脚下踩踏的范围会视为变成D级困难地形，不会妨碍自身及驾驶者，并随着足长的移动而移动。同时，足长踩踏过的地面若有植物，则它们会枯萎坏死，持续一个场景/十分钟，这是一个D级环境来源的效果。你不能在骑乘足长时收回它。</p><p>【炽如地狱的间歇泉」C+1000<br> 獄熱の間欠泉中獄熱就是地狱+极热。极热地狱即佛教“八大地狱”中“大焦热地狱”的别称。<br> 你身边15m范围内视为变成C级困难地形，并随着你的移动而移动。同时你每消耗一点信仰可以抵消一点冻结点数，至多消耗6点。</p><p>土著神「七石七木」</p><p>七石七木的每一项能力均为C+1000</p><p>七つの石と七つの木是「諏訪上社物忌令之事」中记载的七处圣石和七处圣木。过去在请诹访大明神降临时布置在周围的木石，也被用来请诹访大明神回去时所办的神事「御立座神事」使用。七处圣木中，桜湛木、檜湛木已经没有了原来的实物，只剩下遗迹。</p><p>七石：<br> 砚石-【无瑕之体】：现在，【无瑕之体】在获得时，将还会因每失去4点生命上限而获得1点临时生命，这些临时生命每个场景开始时刷新。这些获得的临时生命不会被【鲜血狂怒】限制，也不会被【夜莺之舞】转化。</p><p>御沓石-【唯我独尊】：现在，【唯我独尊】在生效时仍会提供传奇智力原本的效果，但承受的减值将始终增加1点。</p><p>小袋石-【鲜血狂怒】：现在，你将无法再获得【快速医疗】，并将所有现有和以后获得的快速医疗和额外的医疗点（即非快速医疗自带的医疗点）转化为【吸血】，按照每2点快速医疗或每48点额外医疗点转化为1点吸血。每以此法转化1点吸血，就额外获得1点吸血。</p><p>儿玉石-【灵性共鸣】：现在，你在应用【灵性共鸣】时始终需要再支付2点信仰，你可以将你的防御加入崇神手长为你抵御攻击的那次攻击中的计算，在崇神手长为你抵御伤害时。若你对手长在防御应用灵性共鸣，则将一半改为全部防御进行代替。现在，崇神足长攻击时，将可以应用灵性共鸣的效果将你具有的一半攻击数据加入它的检定数据之中。</p><p>御座石-【霸体】：现在，你获得了一项应对技，这是一种类招架行为，具有打断能力，立即利用土石包裹自身以抵御伤害，自身视为如同陷入定身状态一般失去洞察、闪避、基础防御，并将它们全部等量转化为格挡防御。此次招架提供的伤害出目抵销改为提供每点伤害出目抵销*6点格挡防御。在计算超量防御时，这三类防御将不再判定是否满足超量防御。</p><p>龟石-【庸人意志】：现在，八坂神奈子的神影在为你提供全遮蔽时也可以应用【庸人意志】，若如此做，则八坂神奈子的神影可支付的意志力总数上升至五分之二。</p><p>蛙石-【秘法大师】：现在，失去【秘法大师】所固化的法术及相关固化效果，重新选择【秘法大师】法术，这道法术改为自然派系法术，【秘法大师】中所有与黑暗派系有关的部分替换为自然派系。现在，固化的法术提升至B级。</p><p>七木：<br> 桜湛-神樱「湛樱花吹雪」：现在，当你使用铁轮进行施法检定时，铁轮将视为具有等同于诹访大明神或你的最高内在强化等级取高的对应武器伤害（D6C11B18A27S38），并在施法攻击上获得【幻灭】。</p><p>真弓湛-【潜能爆发】：现在，【潜能爆发】带来的剧痛点数造成的减值将被你所免疫，触发【潜能爆发】的那一轮，你视为可以超额承受等同于潜能点/3的伤害（向下取整），即使你的韧性槽已空（最多计入前20点潜能点）。</p><p>峯湛-【我为人人】：现在，【我为人人】生效时，被伤害吸收抵销的前10点伤害也会转化为奉献点，达到第11点时，改为本轮获取的奉献点翻倍，获得的奉献点总数不能超过36点，这个能力生效时，立即对自身造成4点严重伤害。</p><p>檜湛-【诹访大明神】：根据拥有的诹访大明神下属技艺获得对应的能力：<br> 蛙狩「蛙以口鸣，方致蛇祸」：这道法术的效果将可以转附至任意一道诹访大明神下属攻击法术上。</p><p>合掌「大太法师的参拜」（B级）：这道法术的作用范围转变为风度*5米半径的圆，而非作用射程内的5个目标。</p><p>土著神「手长足长大人」：崇神手长和崇神足长提升至C级，其数据如下：<br> 手长<br> ▓▓生理属性<br> ■力量11<br> ■敏捷11<br> ■耐力9<br> ▓▓心智属性<br> ■智力9<br> ■感知9<br> ■决心6<br> ▓▓互动属性<br> ■风度6<br> ■操控6<br> ■沉着6</p><p>▓▓生理系<br> ■运动5 反射5<br> ■求生8 长线治疗8 动物沟通3<br> ■射击1<br> ■武技5 拳5 刀5<br> ▓▓心智系<br> ■学识5 解读5<br> ■器用3<br> ■手艺8 修复制造物品8<br> ■专注1<br> ▓▓互动系<br> ■洞察1<br> ■隐秘1<br> ■表达1<br> ■社交1</p><p>体积5<br> 生命19<br> 防御预设：<br> 基础10+2</p><p>足长<br> ▓▓生理属性<br> ■力量11<br> ■敏捷11<br> ■耐力9<br> ▓▓心智属性<br> ■智力9<br> ■感知9<br> ■决心6<br> ▓▓互动属性<br> ■风度6<br> ■操控6<br> ■沉着6</p><p>▓▓生理系<br> ■运动8 反射8<br> ■求生5 长线治疗5 动物沟通5<br> ■射击1<br> ■武技5 拳5<br> ▓▓心智系<br> ■学识1<br> ■器用5 操纵载具5<br> ■手艺1<br> ■专注1<br> ▓▓互动系<br> ■洞察8 搜索8 侦察8<br> ■隐秘1<br> ■表达1<br> ■社交1</p><p>体积5<br> 生命16<br> 防御预设：<br> 基础10+1</p><p>松木湛-【传奇正盛】：现在，传奇正盛获得如下额外效果：<br> 每当你获得见证点数时，若此见证点数并非你兑换的，而是在影片结束时自然获得的，那么你立即再获得9点信仰，并检视下一项是否能满足条件，若可以，则获得其效果，必须逐项检视，某一项不符合时则跳过剩余的，直至不符合或所有的都被获得过为止。<br> ●若上一场影片中，你触发了所有你具有的本源能力，则再获得3点信仰。<br> ●若这场影片结束时，你获得的奖励资源最多，则再获得3点信仰。<br> ●若这场下场影片开始前，你的评级为同队最高（前提为有队伍），则再获得3点信仰。</p><p>橡木湛-【压胜红包】：现在，当你因【压胜红包】的效果而在其中存入硬币时，还可以再存入等同于30年数的寿命的硬币，这代表了你很长寿。</p><p>柳湛-【改造、材质与附魔】：现在，铁轮也可以被施以材质，附加附魔与添加改造。现在，若铁轮具有【时候未到】，且【时候未到】被触发而生效时，你可以额外选择七石七木中你不具有的一项在这一轮中生效，前提是它能够正常生效。</p><p>专属专长</p><p>神樱「湛樱花吹雪」(1)<br> 湛えの桜是诹访七木之一的「桜湛木」。<br> 你现在可以使用铁轮以风度-器用-专业：铁轮-辅助专业：神术（学识）进行施法检定，若未购买铁轮相关加强，此时铁轮视为一件法强为0的临时武器。使用铁轮施法时，射程不随投掷距离而改变，而是由法术规定射程决定。</p><p>风神符「御射军神柱」(2)<br> 神社里经常供奉着的八角带有草绳的巨大御柱。这玩意居然能随着铁轮一起被扔出去吗？<br> 你现在可以使用敏捷/力量属性+运动+专业：投掷+专业：铁轮（武技）进行投掷武器检定，扔出带有御柱的虚影的铁轮，同时你的攻击范围内新增3个攻击目标。</p><p>源符「厌川的翡翠」（2）<br> 现在，铁轮具有【回力】，且在投掷铁轮进行攻击时，它还会弹射攻击至攻击目标最近的，且处于你的攻击范围内的三个能够被攻击的合法目标。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',67)])])}const C=p(n,[["render",o]]);export{D as __pageData,C as default};
